fn read_string() -> String {
    let mut input = String::new();
    std::io::stdin().read_line(&mut input).expect("Failed");
    input
}

fn main(){
    let now_time = read_string().replace("\n", "").replace("\r", "");
    let sleep_time = read_string().replace("\n", "").replace("\r", "");
    let now_vec: Vec<&str> = now_time.split(":").collect();
    let sleep_vec: Vec<&str> = sleep_time.split(":").collect();
    let fix = if now_vec[1].parse::<i16>().unwrap() < sleep_vec[1].parse::<i16>().unwrap() {1} else {0};
    let mut hours = now_vec[0].parse::<i16>().unwrap() - (sleep_vec[0].parse::<i16>().unwrap()+fix);
    let mut minutes =  now_vec[1].parse::<i16>().unwrap() - sleep_vec[1].parse::<i16>().unwrap();
    if hours < 0{
        hours = 24+hours;
    }
    if minutes < 0{
        minutes = 60+minutes;
    }
    println!("{}{}:{}{}", if hours<10 {"0"} else {""}, hours, if minutes<10 {"0"} else {""},minutes);
    }
